import { streamText } from 'ai';
import { createStreamableValue } from 'ai/rsc';

export async function detectHallucinations(messages: any[]) {
  const result = await streamText({
    model: openai('gpt-4o'),
    messages,
  });

  let chunkCount = 0;
  let hallucinationScore = 0;

  for await (const chunk of result.textStream) {
    chunkCount++;
    // Detect rapid fact changes via token entropy
    if (chunk.length > 50 && hasHighEntropy(chunk)) {
      hallucinationScore += 0.3;
      console.warn(`Potential hallucination in chunk ${chunkCount}:`, chunk.slice(0, 100));
    }
  }

  return hallucinationScore > 0.5;
}

function hasHighEntropy(text: string): boolean {
  // Simple entropy check for hallucination proxy
  const charCount = new Map();
  for (const char of text) charCount.set(char, (charCount.get(char) || 0) + 1);
  const entropy = -Array.from(charCount.values()).reduce((sum, count) => 
    sum + (count / text.length) * Math.log2(count / text.length), 0
  );
  return entropy > 3.5;
}

