import { generateText } from 'ai';

export async function trackAgentLatency(messages: any[]) {
  const start = Date.now();
  let partials = 0;

  try {
    const { text } = await generateText({
      model: openai('gpt-4o'),
      messages,
      maxTokens: 2000,
    });

    const duration = Date.now() - start;
    if (duration > 25000) {
      console.error(`AGENT TIMEOUT: ${duration}ms`, { messages: messages.length });
    }
    return { duration, text };
  } catch (error: any) {
    console.error('AGENT FAILED:', error.message, { duration: Date.now() - start });
    throw error;
  }
}

