import { createStreamableValue } from 'ai/rsc';

export async function safeStreamText(messages: any[]) {
  const streamableText = createStreamableValue('');

  (async () => {
    const result = await streamText({
      model: openai('gpt-4o'),
      messages,
    });

    let buffer = '';
    for await (const chunk of result.textStream) {
      buffer += chunk;
      // Filter hallucinations using simple fact-check proxy
      if (!containsHallucination(buffer)) {
        await streamableText.update(chunk);
      }
    }
    streamableText.done();
  })();

  return streamableText.value;
}

function containsHallucination(text: string): boolean {
  const hallucinationPatterns = [
    /\b(impossible|never|always|100% guaranteed)\b/i,
    /\b[source]|citation/i,
  ];
  return hallucinationPatterns.some(pattern => pattern.test(text));
}

