async function edgeSafeAgent(messages: any[]) {
  // Chunk complex reasoning into steps
  const steps = chunkMessages(messages, 4);
  const streamable = createStreamableValue([]);

  for (const stepMessages of steps) {
    const { text } = await generateText({
      model: openai('gpt-4o'),
      messages: stepMessages,
      maxTokens: 500, // Edge-friendly limits
      temperature: 0.1,
    });

    await streamable.update([{ step: stepMessages.length, text }]);

    if (Date.now() % 20000 > 19000) {
      await new Promise(r => setTimeout(r, 1000)); // Edge cooldown
    }
  }

  streamable.done();
  return streamable.value;
}

function chunkMessages(messages: any[], maxLength = 4): any[][] {
  const chunks: any[][] = [];
  for (let i = 0; i < messages.length; i += maxLength) {
    chunks.push(messages.slice(i, i + maxLength));
  }
  return chunks;
}

